      text: { en: `Commitment & Ownership is strong. People feel genuine accountability, and incentive structures reinforce the right behaviours.`, fr: `Commitment & Ownership is strong. People feel genuine accountability, and incentive structures reinforce the right behaviours.` },
      actions: { en: `Maintain ownership by keeping people involved in ongoing deployment decisions. Monitor incentive alignment as deployment evolves.`, fr: `Maintain ownership by keeping people involved in ongoing deployment decisions. Monitor incentive alignment as deployment evolves.` },
